import{_ as t,o,c as d,ae as r}from"./chunks/framework.DTwQaIIa.js";const g=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/getting-started.md","filePath":"en/guide/getting-started.md"}'),a={name:"en/guide/getting-started.md"};function i(c,e,n,s,l,m){return o(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>This page helps server administrators quickly understand the deployment process and recommended activation order for Emaki Series.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Requirement</th></tr></thead><tbody><tr><td>Java</td><td><code>25</code> or higher (GraalVM recommended)</td></tr><tr><td>Server</td><td>Spigot 1.21+ (or compatible forks such as Paper)</td></tr><tr><td>Runtime Libraries</td><td>Adventure, exp4j, BoostedYaml (automatically loaded by CoreLib via <code>plugin.yml libraries</code>)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">提示</p><p>When deploying <code>EmakiCoreLib 3.2.0</code> for the first time, make sure the server allows downloading runtime libraries via <code>plugin.yml libraries</code>, or prepare the corresponding library cache in advance.</p></div><h2 id="recommended-activation-order" tabindex="-1">Recommended Activation Order <a class="header-anchor" href="#recommended-activation-order" aria-label="Permalink to &quot;Recommended Activation Order&quot;">​</a></h2><p>Follow this order to enable modules step by step, minimizing troubleshooting effort:</p><h3 id="step-1-infrastructure-and-attribute-layer" tabindex="-1">Step 1: Infrastructure and Attribute Layer <a class="header-anchor" href="#step-1-infrastructure-and-attribute-layer" aria-label="Permalink to &quot;Step 1: Infrastructure and Attribute Layer&quot;">​</a></h3><ol><li><strong>EmakiCoreLib</strong> — Hard dependency for all modules, must be installed first</li><li><strong>EmakiAttribute</strong> — Attribute and combat system, provides the numerical foundation for subsequent equipment progression</li></ol><p>Verification: Confirm CoreLib loads correctly, and Attribute definitions and combat calculations work properly.</p><h3 id="step-2-equipment-progression-loop" tabindex="-1">Step 2: Equipment Progression Loop <a class="header-anchor" href="#step-2-equipment-progression-loop" aria-label="Permalink to &quot;Step 2: Equipment Progression Loop&quot;">​</a></h3><ol start="3"><li><strong>EmakiForge</strong> — Forging system</li><li><strong>EmakiStrengthen</strong> — Strengthening system</li></ol><p>Verification: Confirm forging recipes execute correctly, and the strengthening process and star-level progression work properly.</p><h3 id="step-3-world-interaction-and-gem-progression" tabindex="-1">Step 3: World Interaction and Gem Progression <a class="header-anchor" href="#step-3-world-interaction-and-gem-progression" aria-label="Permalink to &quot;Step 3: World Interaction and Gem Progression&quot;">​</a></h3><ol start="5"><li><strong>EmakiGem</strong> — Gem system</li><li><strong>EmakiCooking</strong> — Cooking system</li></ol><p>Verification: Confirm gem inlaying/extraction/upgrading processes work correctly, and cooking stations are interactable.</p><h3 id="step-4-active-skill-system" tabindex="-1">Step 4: Active Skill System <a class="header-anchor" href="#step-4-active-skill-system" aria-label="Permalink to &quot;Step 4: Active Skill System&quot;">​</a></h3><ol start="7"><li><strong>EmakiSkills</strong> + MythicMobs content packs</li></ol><div class="warning custom-block"><p class="custom-block-title">注意</p><p>EmakiSkills is a skill management layer; the actual skill effects are handled by MythicMobs configurations. Skills can still be enabled without MythicMobs, but actual skill casting will fail.</p></div><h2 id="module-dependency-matrix" tabindex="-1">Module Dependency Matrix <a class="header-anchor" href="#module-dependency-matrix" aria-label="Permalink to &quot;Module Dependency Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Hard Dependencies</th><th>Soft Dependencies</th></tr></thead><tbody><tr><td>EmakiCoreLib</td><td>—</td><td>Vault, ExcellentEconomy, PlaceholderAPI, MMOItems, ItemsAdder, Nexo, NeigeItems, CraftEngine</td></tr><tr><td>EmakiAttribute</td><td>EmakiCoreLib</td><td>MythicMobs, PlaceholderAPI, MMOItems</td></tr><tr><td>EmakiForge</td><td>EmakiCoreLib</td><td>EmakiAttribute, PlaceholderAPI</td></tr><tr><td>EmakiStrengthen</td><td>EmakiCoreLib</td><td>EmakiAttribute, PlaceholderAPI</td></tr><tr><td>EmakiCooking</td><td>EmakiCoreLib</td><td>CraftEngine, ItemsAdder, Nexo</td></tr><tr><td>EmakiGem</td><td>EmakiCoreLib</td><td>EmakiAttribute, PlaceholderAPI</td></tr><tr><td>EmakiSkills</td><td>EmakiCoreLib</td><td>MythicMobs, EmakiAttribute, PlaceholderAPI</td></tr></tbody></table><h2 id="command-quick-reference" tabindex="-1">Command Quick Reference <a class="header-anchor" href="#command-quick-reference" aria-label="Permalink to &quot;Command Quick Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Root Command</th><th>Aliases</th></tr></thead><tbody><tr><td>EmakiAttribute</td><td><code>/emakiattribute</code></td><td><code>/eattribute</code>, <code>/ea</code></td></tr><tr><td>EmakiForge</td><td><code>/emakiforge</code></td><td><code>/eforge</code>, <code>/ef</code></td></tr><tr><td>EmakiStrengthen</td><td><code>/emakistrengthen</code></td><td><code>/estrengthen</code></td></tr><tr><td>EmakiCooking</td><td><code>/ecooking</code></td><td><code>/ec</code></td></tr><tr><td>EmakiGem</td><td><code>/emakigem</code></td><td><code>/egem</code>, <code>/eg</code></td></tr><tr><td>EmakiSkills</td><td><code>/emakiskills</code></td><td><code>/eskills</code></td></tr></tbody></table><h2 id="default-resource-locations" tabindex="-1">Default Resource Locations <a class="header-anchor" href="#default-resource-locations" aria-label="Permalink to &quot;Default Resource Locations&quot;">​</a></h2><p>Each module&#39;s configuration and resource files are automatically extracted to the server&#39;s <code>plugins/&lt;module-name&gt;/</code> directory on first startup:</p><table tabindex="0"><thead><tr><th>Module</th><th>Main Resource Directories</th></tr></thead><tbody><tr><td>EmakiCoreLib</td><td><code>config.yml</code>, <code>lang/</code></td></tr><tr><td>EmakiAttribute</td><td><code>attributes/</code>, <code>conditions/</code>, <code>damage_types/</code>, <code>lore_formats/</code>, <code>profiles/</code>, <code>config.yml</code></td></tr><tr><td>EmakiForge</td><td><code>recipes/</code>, <code>gui/</code>, <code>lang/</code>, <code>config.yml</code></td></tr><tr><td>EmakiStrengthen</td><td><code>recipes/</code>, <code>gui/</code>, <code>lang/</code>, <code>config.yml</code></td></tr><tr><td>EmakiCooking</td><td><code>recipes/</code>, <code>gui/</code>, <code>lang/</code>, <code>item_adjustments/</code>, <code>config.yml</code></td></tr><tr><td>EmakiGem</td><td><code>gems/</code>, <code>items/</code>, <code>gui/</code>, <code>conditions/</code>, <code>lang/</code>, <code>config.yml</code></td></tr><tr><td>EmakiSkills</td><td><code>skills/</code>, <code>resources/</code>, <code>gui/</code>, <code>lang/</code>, <code>config.yml</code></td></tr></tbody></table><h2 id="upgrade-notes" tabindex="-1">Upgrade Notes <a class="header-anchor" href="#upgrade-notes" aria-label="Permalink to &quot;Upgrade Notes&quot;">​</a></h2><ul><li>Back up custom configurations, language files, and default resource copies before upgrading</li><li>Migrate all custom vanilla item/block sources to <code>minecraft-xxx</code>, <code>mc-xxx</code>, <code>v-xxx</code>, or bare ID format</li><li>Migrate custom presentations to <code>structured_presentation</code></li><li>For detailed upgrade instructions, see the <a href="/Emaki_Series/en/guide/changelog.html">Changelog</a></li></ul>',28)])])}const h=t(a,[["render",i]]);export{g as __pageData,h as default};
